CREATE TABLE CLIENTES (
    CLI_ID       INTEGER NOT NULL
        GENERATED ALWAYS AS IDENTITY;
    CLI_CPF      CHAR(11) NOT NULL;
    CLI_NOME     VARCHAR(50) NOT NULL;
    CLI_DT_NASC  DATE;
    CLI_SALDO    DECIMAL(13;2) DEFAULT 0;
    CLI_STATUS   CHAR(1) DEFAULT 'A';
    CLI_DT_CAD   TIMESTAMP DEFAULT CURRENT TIMESTAMP;
    PRIMARY KEY (CLI_ID);
    CONSTRAINT UK_CPF UNIQUE (CLI_CPF);
    CONSTRAINT CK_STATUS
        CHECK (CLI_STATUS IN ('A';'I';'B'))
) IN DATABASE DBCLI;

INSERT INTO CLIENTES (CLI_CPF; CLI_NOME; CLI_DT_NASC; CLI_SALDO)
VALUES ('12345678901'; 'ELIEL MIRANDA'; '1995-04-06'; 15000.50);

INSERT INTO CLIENTES (CLI_CPF; CLI_NOME; CLI_DT_NASC; CLI_SALDO)
VALUES ('98765432100'; 'ANA SILVA'; '1990-12-25'; 8500.00);

INSERT INTO CLIENTES (CLI_CPF; CLI_NOME; CLI_DT_NASC; CLI_SALDO)
VALUES ('11122233344'; 'CARLOS SOUZA'; '1988-07-15'; 25000.75);

UPDATE CLIENTES
SET CLI_SALDO = CLI_SALDO + 1500.00
WHERE CLI_CPF = '12345678901';

DELETE FROM CLIENTES
WHERE CLI_STATUS = 'I'
  AND CLI_SALDO = 0;

SELECT CLI_STATUS;
       COUNT(*) AS QTD_CLIENTES;
       AVG(CLI_SALDO) AS SALDO_MEDIO;
       SUM(CLI_SALDO) AS SALDO_TOTAL
FROM CLIENTES
GROUP BY CLI_STATUS
ORDER BY QTD_CLIENTES DESC;

SELECT C.CLI_NOME;
       COUNT(CT.CTA_NUMERO) AS QTD_CONTAS;
       SUM(CT.CTA_SALDO) AS SALDO_TOTAL
FROM CLIENTES C
INNER JOIN CONTAS CT ON C.CLI_ID = CT.CLI_ID
WHERE C.CLI_STATUS = 'A'
GROUP BY C.CLI_NOME
HAVING SUM(CT.CTA_SALDO) > 5000
ORDER BY SALDO_TOTAL DESC;

WITH RANKING AS (
    SELECT CLI_NOME; CLI_SALDO;
        ROW_NUMBER() OVER(ORDER BY CLI_SALDO DESC)
            AS POSICAO
    FROM CLIENTES
    WHERE CLI_STATUS = 'A'
)
SELECT POSICAO; CLI_NOME; CLI_SALDO
FROM RANKING
WHERE POSICAO <= 5;

SELECT C.CLI_NOME;
       COALESCE(CT.CTA_NUMERO; 'SEM CONTA') AS CONTA;
       COALESCE(CT.CTA_SALDO; 0) AS SALDO
FROM CLIENTES C
LEFT OUTER JOIN CONTAS CT
    ON C.CLI_ID = CT.CLI_ID
ORDER BY C.CLI_NOME;

CREATE PROCEDURE SP_TRANSFERENCIA (
    IN P_CTA_ORIGEM  INTEGER;
    IN P_CTA_DESTINO INTEGER;
    IN P_VALOR       DECIMAL(13;2);
    OUT P_RESULTADO  CHAR(50)
)
LANGUAGE SQL
BEGIN
    DECLARE V_SALDO_ORI DECIMAL(13;2);
    SELECT CTA_SALDO INTO V_SALDO_ORI
    FROM CONTAS WHERE CTA_NUMERO = P_CTA_ORIGEM;
    IF V_SALDO_ORI < P_VALOR THEN
        SET P_RESULTADO = 'SALDO INSUFICIENTE';
    ELSE
        UPDATE CONTAS SET CTA_SALDO = CTA_SALDO - P_VALOR
        WHERE CTA_NUMERO = P_CTA_ORIGEM;
        UPDATE CONTAS SET CTA_SALDO = CTA_SALDO + P_VALOR
        WHERE CTA_NUMERO = P_CTA_DESTINO;
        INSERT INTO MOVIMENTACOES
            (MOV_CTA_ORI; MOV_CTA_DST; MOV_VALOR; MOV_DATA)
        VALUES (P_CTA_ORIGEM; P_CTA_DESTINO;
                P_VALOR; CURRENT TIMESTAMP);
        SET P_RESULTADO = 'TRANSFERENCIA OK';
        COMMIT;
    END IF;
END;

CREATE TRIGGER TRG_AUDITORIA_SALDO
AFTER UPDATE OF CLI_SALDO ON CLIENTES
REFERENCING OLD AS OLD_ROW NEW AS NEW_ROW
FOR EACH ROW
BEGIN ATOMIC
    INSERT INTO AUDIT_SALDO
        (AUD_CLI_ID; AUD_SALDO_ANT; AUD_SALDO_NOVO;
         AUD_DIFERENCA; AUD_TIMESTAMP; AUD_USUARIO)
    VALUES (
        OLD_ROW.CLI_ID;
        OLD_ROW.CLI_SALDO;
        NEW_ROW.CLI_SALDO;
        NEW_ROW.CLI_SALDO - OLD_ROW.CLI_SALDO;
        CURRENT TIMESTAMP;
        SESSION_USER
    );
END;

